-- İade Şartları
('85b0ef9a-8f08-431b-b7d9-184b16b08426', 'İade Şartları', 'iade-sartlari',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">İade ve Cayma Hakkı Şartları</h1><div class="prose max-w-none"><h2 class="text-2xl font-bold mb-4 mt-8">1. Genel Hükümler</h2><p class="text-muted-foreground mb-6">Dijital ürünlerin satışında, ürünün niteliği gereği cayma hakkı uygulanmamaktadır. 6502 sayılı Tüketicinin Korunması Hakkında Kanun ve Mesafeli Sözleşmeler Yönetmeliği uyarınca, dijital içerik ve hizmetler cayma hakkı kapsamı dışındadır.</p><h2 class="text-2xl font-bold mb-4 mt-8">2. Dijital Ürünlerde İade</h2><p class="text-muted-foreground mb-6">Satın aldığınız dijital ürünler (oyun kodları, yazılım lisansları, hediye kartları vb.) hemen teslimat yapıldığından ve kullanıma sunulduğundan iade edilemez. Ancak aşağıdaki durumlarda iade ve değişim talep edebilirsiniz:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Teslim edilen ürün kodunun çalışmaması</li><li>Yanlış ürünün teslimatı</li><li>Teknik arıza nedeniyle ürünün kullanılamaması</li><li>Platformumuzdan kaynaklanan hataların olması</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">3. İade Süreci</h2><p class="text-muted-foreground mb-6">Yukarıda belirtilen durumlarla karşılaştığınızda, satın alma tarihinden itibaren 7 gün içerisinde destek ekibimize başvurabilirsiniz. İade talepleriniz için:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Sipariş numaranızı belirtiniz</li><li>Sorunun detaylı açıklamasını yapınız</li><li>Varsa hata ekran görüntüsünü paylaşınız</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">4. İade Onayı ve Süre</h2><p class="text-muted-foreground mb-6">İade talebiniz incelendikten sonra 2-5 iş günü içerisinde size dönüş yapılacaktır. Onaylanan iade talepleri için:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Ürün değişimi yapılabilir</li><li>Ödeme iadesi hesabınıza yapılabilir</li><li>Hesap bakiyenize iade edilebilir</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">5. İade Edilemeyecek Durumlar</h2><p class="text-muted-foreground mb-6">Aşağıdaki durumlarda iade talepleri kabul edilmeyecektir:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Ürün kodunun kullanılmış olması</li><li>Müşteri hatası nedeniyle yanlış ürün alınması</li><li>Ürün açıklamasında belirtilen özelliklerle uyumlu teslimat yapılması</li><li>7 günlük sürenin geçmesi</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">6. İletişim</h2><p class="text-muted-foreground mb-6">İade ve cayma hakkı ile ilgili sorularınız için destek ekibimizle iletişime geçebilirsiniz.</p></div></div>'),
 NULL, NULL, NULL,
 'İade Şartları', 'Dijital ürün satın alımlarında iade ve cayma hakkı koşulları.', 1, '2025-10-15 13:07:17.000', '2025-10-15 13:07:17.000'),

-- Gizlilik Sözleşmesi (güncellendi - gerçek içerik)
('a6d9b2c3-7946-4e04-a8c3-d5962d6900d4', 'Gizlilik Sözleşmesi', 'gizlilik-sozlesmesi',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">Gizlilik Sözleşmesi</h1><div class="prose max-w-none"><p class="text-muted-foreground mb-6">Bu gizlilik politikası, platformumuzu kullanırken toplanan, işlenen ve saklanan kişisel verilerinize ilişkin bilgileri açıklamaktadır. Platformumuzu kullanarak bu politikayı kabul etmiş sayılırsınız.</p><h2 class="text-2xl font-bold mb-4 mt-8">1. Toplanan Veriler</h2><p class="text-muted-foreground mb-6">Platformumuzu kullanırken aşağıdaki veriler toplanabilir:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Ad, soyad ve iletişim bilgileri (e-posta, telefon)</li><li>Hesap giriş bilgileri (şifrelenmiş)</li><li>Satın alma geçmişi ve sipariş detayları</li><li>IP adresi, tarayıcı bilgisi ve cihaz türü</li><li>Çerezler aracılığıyla elde edilen kullanım verileri</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">2. Verilerin Kullanım Amacı</h2><p class="text-muted-foreground mb-6">Toplanan veriler aşağıdaki amaçlarla kullanılmaktadır:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Sipariş ve teslimat işlemlerinin yönetimi</li><li>Müşteri hizmetleri ve destek sağlanması</li><li>Yasal yükümlülüklerin yerine getirilmesi</li><li>Platformun güvenliğinin sağlanması</li><li>Kullanıcı deneyiminin iyileştirilmesi</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">3. Verilerin Paylaşımı</h2><p class="text-muted-foreground mb-6">Kişisel verileriniz; yasal zorunluluklar dışında ve açık rızanız olmaksızın üçüncü taraflarla paylaşılmaz. Ödeme işlemleri için güvenli ödeme altyapı sağlayıcılarıyla sınırlı veri paylaşımı yapılabilir.</p><h2 class="text-2xl font-bold mb-4 mt-8">4. Veri Güvenliği</h2><p class="text-muted-foreground mb-6">Kişisel verilerinizin güvenliği için SSL şifreleme, güvenli sunucu altyapısı ve erişim kısıtlamaları gibi teknik tedbirler uygulanmaktadır.</p><h2 class="text-2xl font-bold mb-4 mt-8">5. Çerezler</h2><p class="text-muted-foreground mb-6">Platformumuz, kullanıcı deneyimini iyileştirmek amacıyla çerezler kullanmaktadır. Tarayıcı ayarlarınızdan çerezleri devre dışı bırakabilirsiniz; ancak bazı özellikler düzgün çalışmayabilir.</p><h2 class="text-2xl font-bold mb-4 mt-8">6. Haklarınız</h2><p class="text-muted-foreground mb-6">6698 sayılı KVKK kapsamında kişisel verilerinize erişim, düzeltme, silme ve işlemeye itiraz etme haklarına sahipsiniz. Taleplerinizi destek kanallarımız aracılığıyla iletebilirsiniz.</p><h2 class="text-2xl font-bold mb-4 mt-8">7. İletişim</h2><p class="text-muted-foreground mb-6">Gizlilik politikamıza ilişkin sorularınız için destek ekibimizle iletişime geçebilirsiniz.</p></div></div>'),
 NULL, NULL, NULL,
 'Gizlilik Sözleşmesi', 'Kişisel verilerinizin nasıl toplandığı, işlendiği ve korunduğuna dair gizlilik politikamız.', 1, '2025-10-09 18:40:45.000', NOW(3)),

-- Hizmet Sözleşmesi
('d08dba17-56d9-48c1-b30e-824b390e0009', 'Hizmet Sözleşmesi', 'hizmet-sozlesmesi',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">Mesafeli Satış Sözleşmesi</h1><div class="prose max-w-none"><h2 class="text-2xl font-bold mb-4 mt-8">1. Taraflar</h2><p class="text-muted-foreground mb-6">İşbu sözleşme, dijital ürünler platformumuz (bundan sonra "SATICI" olarak anılacaktır) ile platformumuzu kullanan müşteri (bundan sonra "ALICI" olarak anılacaktır) arasında akdedilmiştir.</p><h2 class="text-2xl font-bold mb-4 mt-8">2. Sözleşmenin Konusu</h2><p class="text-muted-foreground mb-6">İşbu sözleşme, ALICI''nın SATICI''ya ait internet sitesi üzerinden elektronik ortamda siparişini verdiği dijital ürünlerin satışı ve teslimi ile ilgili olarak 6502 sayılı Tüketicinin Korunması Hakkında Kanun ve Mesafeli Sözleşmelere Dair Yönetmelik hükümleri gereğince tarafların hak ve yükümlülüklerini düzenler.</p><h2 class="text-2xl font-bold mb-4 mt-8">3. Ürün Bilgileri</h2><p class="text-muted-foreground mb-6">Satışa konu ürünlerin temel özellikleri (türü, miktarı, marka/modeli, rengi, adedi) ürün sayfasında yer almaktadır. ALICI, sipariş vermeden önce ürün bilgilerini incelemiş ve bilgilendirilmiş sayılır.</p><h2 class="text-2xl font-bold mb-4 mt-8">4. Fiyat ve Ödeme</h2><p class="text-muted-foreground mb-6">Ürünlerin satış fiyatı, ürün sayfasında gösterilen fiyattır. Fiyatlar KDV dahildir. SATICI, kampanya süresince veya stok durumuna göre fiyatlarda değişiklik yapma hakkını saklı tutar.</p><p class="text-muted-foreground mb-6">Ödeme şekilleri:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Kredi Kartı / Banka Kartı</li><li>Havale / EFT</li><li>Hesap Bakiyesi</li><li>Diğer elektronik ödeme yöntemleri</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">5. Teslimat</h2><p class="text-muted-foreground mb-6">Dijital ürünler, ödeme onayından sonra anında veya belirtilen süre içerisinde elektronik ortamda ALICI''ya teslim edilir. Teslimat, ALICI''nın kayıtlı e-posta adresine veya hesap panelindeki sipariş detayları bölümüne yapılır.</p><h2 class="text-2xl font-bold mb-4 mt-8">6. Cayma Hakkı</h2><p class="text-muted-foreground mb-6">6502 sayılı Tüketicinin Korunması Hakkında Kanun''un 15. maddesi ve Mesafeli Sözleşmeler Yönetmeliği''nin 15. maddesi gereğince, dijital içerik ve hizmetlerin sunulması ile birlikte cayma hakkı sona erer. ALICI, dijital ürünü teslim almakla cayma hakkından vazgeçtiğini kabul eder.</p><h2 class="text-2xl font-bold mb-4 mt-8">7. Garanti ve Sorumluluk</h2><p class="text-muted-foreground mb-6">SATICI, teslim edilen dijital ürünlerin orijinal ve çalışır durumda olduğunu garanti eder. Ürünle ilgili teknik sorunlar için 7 gün içerisinde destek ekibimize başvurulabilir.</p><h2 class="text-2xl font-bold mb-4 mt-8">8. Kişisel Verilerin Korunması</h2><p class="text-muted-foreground mb-6">ALICI''nın kişisel bilgileri, 6698 sayılı Kişisel Verilerin Korunması Kanunu kapsamında işlenir ve korunur. Detaylı bilgi için Gizlilik Politikamızı inceleyebilirsiniz.</p><h2 class="text-2xl font-bold mb-4 mt-8">9. Uyuşmazlıkların Çözümü</h2><p class="text-muted-foreground mb-6">İşbu sözleşmeden doğan uyuşmazlıklarda, Tüketici Hakem Heyetleri ve Tüketici Mahkemeleri yetkilidir. ALICI, sipariş verdiği anda bu sözleşmeyi kabul etmiş sayılır.</p><h2 class="text-2xl font-bold mb-4 mt-8">10. Yürürlük</h2><p class="text-muted-foreground mb-6">İşbu sözleşme, ALICI tarafından elektronik ortamda onaylanmasıyla yürürlüğe girer. SATICI, sözleşmede değişiklik yapma hakkını saklı tutar.</p></div></div>'),
 NULL, NULL, NULL,
 NULL, NULL, 1, '2025-10-15 13:07:17.000', '2025-10-15 13:07:17.000'),

-- KVKK Aydınlatma Metni (YENİ)
('f1e2d3c4-b5a6-7890-abcd-ef1234567891', 'KVKK Aydınlatma Metni', 'kvkk',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">KVKK Aydınlatma Metni</h1><div class="prose max-w-none"><p class="text-muted-foreground mb-6">6698 sayılı Kişisel Verilerin Korunması Kanunu (KVKK) kapsamında veri sorumlusu sıfatıyla platformumuz, kişisel verilerinizin işlenmesine ilişkin sizi aşağıdaki şekilde bilgilendirmektedir.</p><h2 class="text-2xl font-bold mb-4 mt-8">1. Veri Sorumlusu</h2><p class="text-muted-foreground mb-6">Platformumuz, 6698 sayılı KVKK uyarınca veri sorumlusu olarak kişisel verilerinizi işlemektedir.</p><h2 class="text-2xl font-bold mb-4 mt-8">2. İşlenen Kişisel Veriler</h2><p class="text-muted-foreground mb-6">Platformumuz tarafından işlenen kişisel veriler şunlardır:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li><strong>Kimlik Verileri:</strong> Ad, soyad</li><li><strong>İletişim Verileri:</strong> E-posta adresi, telefon numarası</li><li><strong>İşlem Verileri:</strong> Sipariş geçmişi, ödeme bilgileri (kart numarası saklanmaz)</li><li><strong>Teknik Veriler:</strong> IP adresi, tarayıcı bilgisi, çerez verileri</li><li><strong>Hesap Verileri:</strong> Kullanıcı adı, şifrelenmiş parola</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">3. Kişisel Verilerin İşlenme Amaçları</h2><p class="text-muted-foreground mb-6">Kişisel verileriniz aşağıdaki amaçlarla işlenmektedir:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Üyelik ve hesap yönetimi</li><li>Sipariş ve ödeme işlemlerinin gerçekleştirilmesi</li><li>Müşteri hizmetleri ve destek sağlanması</li><li>Yasal yükümlülüklerin yerine getirilmesi</li><li>Güvenlik ve dolandırıcılık önleme</li><li>Platform hizmetlerinin geliştirilmesi</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">4. Hukuki Dayanak</h2><p class="text-muted-foreground mb-6">Kişisel verileriniz; sözleşmenin kurulması ve ifası, hukuki yükümlülüklerin yerine getirilmesi ve meşru menfaat kapsamında KVKK madde 5 ve 6 uyarınca işlenmektedir.</p><h2 class="text-2xl font-bold mb-4 mt-8">5. Verilerin Aktarımı</h2><p class="text-muted-foreground mb-6">Kişisel verileriniz; ödeme altyapı sağlayıcıları, bulut hizmet sağlayıcıları ve yasal merciler dışında üçüncü taraflarla paylaşılmamaktadır. Yurt dışına veri aktarımı, KVKK''nın 9. maddesi kapsamında gerçekleştirilmektedir.</p><h2 class="text-2xl font-bold mb-4 mt-8">6. Veri Saklama Süresi</h2><p class="text-muted-foreground mb-6">Kişisel verileriniz, işlenme amacının gerektirdiği süre boyunca ve yasal yükümlülükler kapsamında saklanmaktadır. Sürenin dolmasının ardından veriler silinmekte, yok edilmekte veya anonim hale getirilmektedir.</p><h2 class="text-2xl font-bold mb-4 mt-8">7. Haklarınız</h2><p class="text-muted-foreground mb-6">KVKK''nın 11. maddesi kapsamında aşağıdaki haklara sahipsiniz:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Kişisel verilerinizin işlenip işlenmediğini öğrenme</li><li>İşlenmişse buna ilişkin bilgi talep etme</li><li>İşlenme amacını ve amacına uygun kullanılıp kullanılmadığını öğrenme</li><li>Yurt içinde veya yurt dışında aktarıldığı üçüncü kişileri bilme</li><li>Eksik veya yanlış işlenmiş verilerin düzeltilmesini isteme</li><li>KVKK''nın 7. maddesi kapsamında silinmesini veya yok edilmesini isteme</li><li>İşlemeye itiraz etme</li><li>Otomatik sistemler ile analiz edilmesi suretiyle aleyhinize sonuç doğurmasına itiraz etme</li><li>Zararın giderilmesini talep etme</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">8. Başvuru Yöntemi</h2><p class="text-muted-foreground mb-6">KVKK kapsamındaki haklarınızı kullanmak için destek kanallarımız aracılığıyla yazılı başvuruda bulunabilirsiniz. Başvurunuz en geç 30 gün içinde sonuçlandırılacaktır.</p></div></div>'),
 NULL, NULL, NULL,
 'KVKK Aydınlatma Metni', '6698 sayılı KVKK kapsamında kişisel verilerinizin işlenmesine ilişkin aydınlatma metni.', 1, NOW(3), NOW(3)),

-- Ödeme Yöntemleri
('c4d5e6f7-a8b9-1234-cdef-567890abcde1', 'Ödeme Yöntemleri', 'odeme-yontemleri',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">Ödeme Yöntemleri</h1><div class="prose max-w-none"><p class="text-muted-foreground mb-6">Platformumuzda güvenli ve kolay ödeme yapabilmeniz için çeşitli ödeme seçenekleri sunulmaktadır. Tüm ödemeler SSL şifreleme ile korunmaktadır.</p><h2 class="text-2xl font-bold mb-4 mt-8">Kredi Kartı ve Banka Kartı</h2><p class="text-muted-foreground mb-6">Visa, Mastercard ve American Express kartlarınızla güvenli ödeme yapabilirsiniz. PayTR ve Stripe altyapısı üzerinden gerçekleştirilen işlemlerde kart bilgileriniz sunucularımızda saklanmaz.</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Tek çekim ödeme</li><li>Taksitli ödeme seçenekleri (banka ve kart limitine göre değişir)</li><li>3D Secure doğrulaması ile güvenli ödeme</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">Havale / EFT</h2><p class="text-muted-foreground mb-6">Banka havalesi veya EFT ile ödeme yapmak istiyorsanız, sipariş sonrasında gösterilecek hesap bilgilerimize transfer yapabilirsiniz. Havale/EFT ödemelerinde işlem 1-2 iş günü içinde onaylanır.</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Sipariş numarasını açıklama kısmına yazınız</li><li>Ad soyad bilgilerinizin gönderim bilgileriyle eşleşmesi gerekmektedir</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">Cüzdan ile Ödeme</h2><p class="text-muted-foreground mb-6">Platformumuzdaki cüzdan bakiyenizi kullanarak anında ödeme yapabilirsiniz. Cüzdanınıza bakiye yüklemek için diğer ödeme yöntemlerini kullanabilirsiniz.</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Anlık ödeme — ek onay gerekmez</li><li>Kısmi ödeme: bakiye yetersizse farkı başka yöntemle tamamlayabilirsiniz</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">Ödeme Güvenliği</h2><p class="text-muted-foreground mb-6">Tüm ödeme işlemleri 256-bit SSL şifreleme ile korunmaktadır. Kart bilgileriniz sunucularımızda saklanmamakta; PCI DSS uyumlu güvenli ödeme altyapısı kullanılmaktadır.</p><h2 class="text-2xl font-bold mb-4 mt-8">Sorun Yaşıyorsanız</h2><p class="text-muted-foreground mb-6">Ödeme sürecinde sorun yaşamanız durumunda destek ekibimizle iletişime geçebilirsiniz. Ödeme işleminiz tamamlanmış ancak siparişiniz oluşmamışsa, banka dekontunuzla birlikte bize ulaşın.</p></div></div>'),
 NULL, NULL, NULL,
 'Ödeme Yöntemleri', 'Güvenli ödeme seçeneklerimiz: kredi kartı (PayTR / Stripe), havale/EFT ve cüzdan ile ödeme.', 1, NOW(3), NOW(3)),

-- Kullanım Koşulları (YENİ)
('b7c8d9e0-f1a2-3456-bcde-f012345678ab', 'Kullanım Koşulları', 'kullanim-kosullari',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">Kullanım Koşulları</h1><div class="prose max-w-none"><p class="text-muted-foreground mb-6">Bu kullanım koşulları, platformumuzu kullanan tüm kullanıcılar için geçerlidir. Platformumuza erişim sağlayarak ve hizmetlerimizi kullanarak bu koşulları kabul etmiş sayılırsınız.</p><h2 class="text-2xl font-bold mb-4 mt-8">1. Genel Kurallar</h2><p class="text-muted-foreground mb-6">Platformumuzu kullanırken aşağıdaki kurallara uymayı kabul edersiniz:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Platformu yalnızca yasal amaçlarla kullanmak</li><li>Başkalarının haklarını ihlal etmemek</li><li>Yanlış veya yanıltıcı bilgi paylaşmamak</li><li>Platform güvenliğini tehdit edecek girişimlerde bulunmamak</li><li>Diğer kullanıcıların deneyimini olumsuz etkileyecek davranışlardan kaçınmak</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">2. Hesap Güvenliği</h2><p class="text-muted-foreground mb-6">Hesabınızın güvenliğinden siz sorumlusunuz. Şifrenizi kimseyle paylaşmamalı, şüpheli bir durumda derhal bize bildirmelisiniz. Hesabınız üzerinden gerçekleştirilen tüm işlemlerden siz sorumlu tutulacaksınız.</p><h2 class="text-2xl font-bold mb-4 mt-8">3. Dijital Ürünlerin Kullanımı</h2><p class="text-muted-foreground mb-6">Satın aldığınız dijital ürünler yalnızca kişisel kullanım içindir. Ürünleri:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Yeniden satmak veya devretmek</li><li>Ticari amaçlarla kullanmak (lisans izni olmaksızın)</li><li>Kopyalayarak çoğaltmak veya dağıtmak</li><li>Tersine mühendislik uygulamak</li></ul><p class="text-muted-foreground mb-6">...yasaklanmıştır. Bu koşulların ihlali hesabınızın askıya alınmasına neden olabilir.</p><h2 class="text-2xl font-bold mb-4 mt-8">4. Fiyatlandırma ve Kampanyalar</h2><p class="text-muted-foreground mb-6">Ürün fiyatları önceden bildirim yapılmaksızın değiştirilebilir. Kampanya ve indirimler belirtilen süre veya stok ile sınırlıdır. Hatalı fiyat görüntülenmesi durumunda sipariş iptal edilebilir.</p><h2 class="text-2xl font-bold mb-4 mt-8">5. Sorumluluk Sınırlaması</h2><p class="text-muted-foreground mb-6">Platformumuz, kullanımdan kaynaklanabilecek doğrudan veya dolaylı zararlardan sorumlu tutulamaz. Hizmet kesintileri, teknik arızalar veya üçüncü taraf kaynaklı sorunlarda azami sorumluluk satın alınan ürün bedeli ile sınırlıdır.</p><h2 class="text-2xl font-bold mb-4 mt-8">6. Fikri Mülkiyet</h2><p class="text-muted-foreground mb-6">Platform üzerindeki tüm içerik, logo, tasarım ve kod; telif hakkı ve fikri mülkiyet yasaları kapsamında korunmaktadır. İzinsiz kullanım yasaktır.</p><h2 class="text-2xl font-bold mb-4 mt-8">7. Hesap Askıya Alma ve Kapatma</h2><p class="text-muted-foreground mb-6">Bu koşulları ihlal etmeniz durumunda hesabınız önceden bildirim yapılmaksızın askıya alınabilir veya kalıcı olarak kapatılabilir. Aktif siparişleriniz ve bakiyeniz değerlendirilerek gerekli işlemler yapılır.</p><h2 class="text-2xl font-bold mb-4 mt-8">8. Değişiklikler</h2><p class="text-muted-foreground mb-6">Kullanım koşullarında yapılacak değişiklikler platform üzerinden duyurulacaktır. Değişiklikler yayınlandıktan sonra platformu kullanmaya devam etmeniz, yeni koşulları kabul ettiğiniz anlamına gelir.</p><h2 class="text-2xl font-bold mb-4 mt-8">9. Uyuşmazlık Çözümü</h2><p class="text-muted-foreground mb-6">Bu koşullardan doğan uyuşmazlıklarda Türkiye Cumhuriyeti mahkemeleri yetkilidir ve Türk hukuku uygulanır.</p><h2 class="text-2xl font-bold mb-4 mt-8">10. İletişim</h2><p class="text-muted-foreground mb-6">Kullanım koşullarına ilişkin sorularınız için destek ekibimizle iletişime geçebilirsiniz.</p></div></div>'),
 NULL, NULL, NULL,
 'Kullanım Koşulları', 'Platform kullanım koşulları, kurallar ve yasal bilgilendirme.', 1, NOW(3), NOW(3)),

-- Çerez Politikası (YENİ)
('e9f0a1b2-c3d4-5678-90ab-cdef01234567', 'Çerez Politikası', 'cerez-politikasi',
 JSON_OBJECT('html', '<div class="container mx-auto px-4 py-12"><h1 class="text-4xl font-bold mb-8">Çerez Politikası</h1><div class="prose max-w-none"><p class="text-muted-foreground mb-6">Bu çerez politikası, platformumuzu ziyaret ettiğinizde cihazınıza yerleştirilen çerezlerin nasıl kullanıldığını açıklamaktadır.</p><h2 class="text-2xl font-bold mb-4 mt-8">Çerez Nedir?</h2><p class="text-muted-foreground mb-6">Çerezler, web sitelerinin tarayıcınıza yerleştirdiği küçük metin dosyalarıdır. Platformumuzu tekrar ziyaret ettiğinizde sizi tanımamıza, tercihlerinizi hatırlamamıza ve size daha iyi bir deneyim sunmamıza yardımcı olurlar.</p><h2 class="text-2xl font-bold mb-4 mt-8">Kullandığımız Çerez Türleri</h2><h3 class="text-xl font-semibold mb-3 mt-6">Zorunlu Çerezler</h3><p class="text-muted-foreground mb-4">Platformun düzgün çalışması için gereklidir. Bu çerezler olmadan oturum açma, alışveriş sepeti ve ödeme gibi temel işlevler çalışmaz. Devre dışı bırakılamazlar.</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Oturum yönetimi çerezleri</li><li>Güvenlik çerezleri</li><li>Yük dengeleme çerezleri</li></ul><h3 class="text-xl font-semibold mb-3 mt-6">Analitik Çerezler</h3><p class="text-muted-foreground mb-4">Ziyaretçilerin platformu nasıl kullandığını anlamamıza yardımcı olur. Bu veriler anonim olarak toplanır ve platform performansını iyileştirmek için kullanılır.</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Google Analytics çerezleri</li><li>Sayfa görüntüleme ve tıklama verileri</li><li>Ziyaretçi davranış analizi</li></ul><h3 class="text-xl font-semibold mb-3 mt-6">İşlevsel Çerezler</h3><p class="text-muted-foreground mb-4">Tercihlerinizi hatırlamak ve kişiselleştirilmiş özellikler sunmak için kullanılır.</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li>Dil ve bölge tercihleri</li><li>Tema (açık/koyu) tercihi</li><li>Son görüntülenen ürünler</li></ul><h3 class="text-xl font-semibold mb-3 mt-6">Pazarlama Çerezleri</h3><p class="text-muted-foreground mb-4">İlgi alanlarınıza uygun reklamlar göstermek ve kampanyaların etkinliğini ölçmek amacıyla kullanılabilir.</p><h2 class="text-2xl font-bold mb-4 mt-8">Çerezleri Kontrol Etme</h2><p class="text-muted-foreground mb-6">Çerez tercihlerinizi tarayıcı ayarlarınızdan yönetebilirsiniz. Çerezleri tamamen devre dışı bırakmak mümkün olmakla birlikte, bu durumda platformun bazı özellikleri düzgün çalışmayabilir.</p><p class="text-muted-foreground mb-6">Popüler tarayıcılarda çerez ayarları:</p><ul class="list-disc pl-6 space-y-2 text-muted-foreground mb-6"><li><strong>Chrome:</strong> Ayarlar → Gizlilik ve Güvenlik → Çerezler</li><li><strong>Firefox:</strong> Ayarlar → Gizlilik ve Güvenlik → Çerezler ve Site Verileri</li><li><strong>Safari:</strong> Tercihler → Gizlilik → Çerezler ve Web Sitesi Verileri</li><li><strong>Edge:</strong> Ayarlar → Gizlilik, Arama ve Hizmetler → Çerezler</li></ul><h2 class="text-2xl font-bold mb-4 mt-8">Üçüncü Taraf Çerezler</h2><p class="text-muted-foreground mb-6">Platformumuzda Google Analytics ve benzeri üçüncü taraf hizmetlerin çerezleri kullanılabilir. Bu çerezler ilgili hizmet sağlayıcıların gizlilik politikaları kapsamındadır.</p><h2 class="text-2xl font-bold mb-4 mt-8">Politika Güncellemeleri</h2><p class="text-muted-foreground mb-6">Çerez politikamız zaman zaman güncellenebilir. Önemli değişiklikler platform üzerinden duyurulacaktır.</p><h2 class="text-2xl font-bold mb-4 mt-8">İletişim</h2><p class="text-muted-foreground mb-6">Çerez kullanımına ilişkin sorularınız için destek ekibimizle iletişime geçebilirsiniz.</p></div></div>'),
 NULL, NULL, NULL,
 'Çerez Politikası', 'Platformumuzda kullanılan çerezler ve çerez tercihlerinizi nasıl yönetebileceğiniz.', 1, NOW(3), NOW(3)),

